### Union Types

Union types allow a value to be one of several types. They use the pipe (`|`) operator.

### Basic Syntax

```typescript
type StringOrNumber = string | number;

let value: StringOrNumber;
value = "hello"; // OK
value = 42; // OK
// value = true; // Error
```

### Unions with Objects

```typescript
type Circle = { kind: "circle"; radius: number };
type Square = { kind: "square"; side: number };
type Shape = Circle | Square;

function area(shape: Shape): number {
  if (shape.kind === "circle") {
    return Math.PI * shape.radius ** 2;
  }
  return shape.side ** 2;
}
```

### Discriminated Unions

A common pattern using a literal type property to discriminate:

```typescript
type Success<T> = { status: "success"; data: T };
type Error = { status: "error"; message: string };
type Loading = { status: "loading" };

type AsyncState<T> = Success<T> | Error | Loading;

function handleState<T>(state: AsyncState<T>): string {
  switch (state.status) {
    case "success": return `Data: ${state.data}`;
    case "error": return `Error: ${state.message}`;
    case "loading": return "Loading...";
  }
}
```

### Narrowing Unions

```typescript
function process(value: string | number | boolean): void {
  if (typeof value === "string") {
    console.log(value.toUpperCase());
  } else if (typeof value === "number") {
    console.log(value.toFixed(2));
  } else {
    console.log(value ? "true" : "false");
  }
}
```

> **Key Point:** You must narrow union types before accessing type-specific properties.

codeExample:
// Basic union
let id: string | number;
id = "abc123";
id = 456;

// Union with arrays
type Result = number[] | string[];
const nums: Result = [1, 2, 3];
const strs: Result = ["a", "b"];

// Discriminated union
type ApiResult<T> =
  | { ok: true; data: T }
  | { ok: false; error: string };

function handleResult<T>(result: ApiResult<T>): T | never {
  if (result.ok) return result.data;
  throw new Error(result.error);
}
